const results = [];

for (const item of $('Webhook').all()) {
  // Webhook data can arrive nested under `body` or flat
  const payload = item.json.body?.payload ?? item.json.payload;

  const attendee = payload.attendees?.[0] ?? {};
  const tz = attendee.timeZone || payload.organizer?.timeZone || 'Asia/Kolkata';

  const start = new Date(payload.startTime);

  // Format in the attendee's own timezone
  const meetingDate = new Intl.DateTimeFormat('en-IN', {
    timeZone: tz,
    day: 'numeric',
    month: 'long',
    year: 'numeric',
  }).format(start); // → "10 July 2026"

  const meetingTime = new Intl.DateTimeFormat('en-IN', {
    timeZone: tz,
    hour: 'numeric',
    minute: '2-digit',
    hour12: true,
  }).format(start); // → "3:00 pm"

  const meetingLink =
    payload.videoCallData?.url ||
    payload.metadata?.videoCallUrl ||
    payload.location ||
    '';

  // WhatsApp API wants digits only, no "+"
  const rawPhone = attendee.phoneNumber || payload.responses?.attendeePhoneNumber?.value || '';
  const phone = rawPhone.replace(/\D/g, '');

  results.push({
    json: {
      triggerEvent: item.json.body?.triggerEvent ?? item.json.triggerEvent,
      bookingId: payload.bookingId,
      bookingUid: payload.uid,
      status: payload.status,

      customerName: attendee.firstName || attendee.name || 'there',
      customerEmail: attendee.email || '',
      customerPhone: phone,

      meetingTitle: payload.eventTypeTitle || payload.title,
      meetingDate,
      meetingTime,
      meetingLink,
      timeZone: tz,

      startTimeISO: payload.startTime,
      endTimeISO: payload.endTime,
      durationMinutes: payload.length,
      agenda: payload.userFieldsResponses?.['Call-Agenda']?.value || '',
    },
  });
}

return results;

// --- Config ---
const WINDOWS = [
  { label: '15_min', fromMin: 0,  toMin: 15 },
  { label: '60_min', fromMin: 58, toMin: 73 },
];

const SKIP_DECLINED = true;
const DEFAULT_TZ = 'Asia/Kolkata';   // fallback if event omits timeZone

const PHONE_RE = /\+\d[\d\s\-().]{6,}\d/;
const EMAIL_RE = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
const PLACEHOLDER_RE = /^(guest|organizer|attendee)$/i;

function parsePeopleByEmail(description) {
  const map = {};
  if (!description) return map;

  const lines = description.split('\n').map(l => l.trim());
  let pending = null;

  for (const line of lines) {
    if (!line) continue;

    if (EMAIL_RE.test(line)) {
      const key = line.toLowerCase();
      if (pending) {
        const prev = map[key];
        map[key] = {
          name:  pending.name  || prev?.name  || null,
          phone: pending.phone || prev?.phone || null,
        };
      } else if (!map[key]) {
        map[key] = { name: null, phone: null };
      }
      pending = null;
      continue;
    }

    const m = line.match(PHONE_RE);
    const phone = m ? m[0].replace(/[\s\-().]/g, '') : null;

    let name = (m ? line.slice(0, m.index) : line)
      .replace(/[-–—:]\s*$/, '')
      .replace(/\s*[-–—]\s*Organizer$/i, '')
      .trim();

    if (!name || PLACEHOLDER_RE.test(name)) name = null;

    pending = { name, phone };
  }

  return map;
}

// --- Date/time helpers (all timezone-aware) ---
const fmt = (date, tz, opts) =>
  new Intl.DateTimeFormat('en-IN', { timeZone: tz, ...opts }).format(date);

// "1:00 pm"
const timeStr = (d, tz) =>
  fmt(d, tz, { hour: 'numeric', minute: '2-digit', hour12: true })
    .replace(/\s?(AM|PM)/i, s => ' ' + s.trim().toLowerCase());

// "10 July 2026"
const dateStr = (d, tz) =>
  fmt(d, tz, { day: 'numeric', month: 'long', year: 'numeric' });

// "Friday"
const dayStr = (d, tz) => fmt(d, tz, { weekday: 'long' });

// "2026-07-10" — for grouping / DB keys
const isoDate = (d, tz) => fmt(d, tz, { year: 'numeric', month: '2-digit', day: '2-digit' })
  .split('/').reverse().join('-');

// 75 -> "1 hour 15 minutes"
function humanDuration(totalMin) {
  const mins = Math.max(0, Math.round(totalMin));
  const h = Math.floor(mins / 60);
  const m = mins % 60;
  const parts = [];
  if (h) parts.push(`${h} hour${h > 1 ? 's' : ''}`);
  if (m) parts.push(`${m} minute${m > 1 ? 's' : ''}`);
  return parts.join(' ') || '0 minutes';
}

const now = Date.now();
const out = [];

for (const item of $input.all()) {
  const ev = item.json;

  if (ev.status && ev.status !== 'confirmed') continue;

  const startRaw = ev.start?.dateTime;
  if (!startRaw) continue;

  const startMs = new Date(startRaw).getTime();
  if (Number.isNaN(startMs)) continue;
  if (startMs <= now) continue;

  if (SKIP_DECLINED) {
    const self = (ev.attendees || []).find(a => a.self);
    if (self && self.responseStatus === 'declined') continue;
  }

  const minutesUntil = (startMs - now) / 60000;
  const win = WINDOWS.find(w => minutesUntil >= w.fromMin && minutesUntil < w.toMin);
  if (!win) continue;

  const tz = ev.start?.timeZone || DEFAULT_TZ;
  const startDate = new Date(startMs);
  const endRaw = ev.end?.dateTime || null;
  const endDate = endRaw ? new Date(endRaw) : null;

  const durationMin = endDate ? (endDate - startDate) / 60000 : null;
  const minsLeft = Math.round(minutesUntil);

  // "Today" / "Tomorrow" / "Friday" — relative to the event's own timezone
  const todayKey = isoDate(new Date(now), tz);
  const eventKey = isoDate(startDate, tz);
  const tomorrowKey = isoDate(new Date(now + 86400000), tz);
  const relativeDay =
    eventKey === todayKey ? 'Today'
    : eventKey === tomorrowKey ? 'Tomorrow'
    : dayStr(startDate, tz);

  const people = parsePeopleByEmail(ev.description);

  const guests = (ev.attendees || [])
    .filter(a => !a.self)
    .map(a => {
      const info = people[a.email?.toLowerCase()] || {};
      return {
        name: info.name || null,
        email: a.email,
        phone: info.phone || null,
        responseStatus: a.responseStatus || null,
      };
    });

  const primary =
    guests.find(g => g.phone) || guests.find(g => g.name) || guests[0] || null;

  out.push({
    json: {
      reminderType: win.label,
      eventId: ev.id,
      title: ev.summary,

      // --- Person ---
      inviteeName: primary?.name || null,
      inviteeEmail: primary?.email || null,
      inviteePhone: primary?.phone || null,
      hasPhone: Boolean(primary?.phone),

      // --- Formatted for messaging ---
      startTimeFormatted: timeStr(startDate, tz),          // "1:00 pm"
      endTimeFormatted: endDate ? timeStr(endDate, tz) : null,
      dateFormatted: dateStr(startDate, tz),               // "10 July 2026"
      dayOfWeek: dayStr(startDate, tz),                    // "Friday"
      relativeDay,                                         // "Today"
      durationFormatted: durationMin ? humanDuration(durationMin) : null,
      startsInFormatted: humanDuration(minsLeft),          // "1 hour 13 minutes"

      // --- Raw, for logic downstream ---
      minutesUntil: minsLeft,
      durationMinutes: durationMin,
      startTime: startRaw,
      endTime: endRaw,
      eventDate: eventKey,                                 // "2026-07-10"
      timeZone: tz,

      meetLink: ev.hangoutLink || ev.location || null,
      description: ev.description || '',
      attendees: guests,
      htmlLink: ev.htmlLink,
    },
  });
}

return out;

