const now = Date.now();
const out = [];

for (const item of $input.all()) {
  const b = item.json;

  if (!VALID_STATUSES.includes(b.status)) continue;

  if (!b.startTimeISO) continue;
  const startMs = new Date(b.startTimeISO).getTime();
  if (Number.isNaN(startMs) || startMs <= now) continue;

  const minutesUntil = (startMs - now) / 60000;
  const win = WINDOWS.find(w => minutesUntil >= w.fromMin && minutesUntil < w.toMin);
  if (!win) continue;

  const tz = b.timeZone || DEFAULT_TZ;
  const startDate = new Date(startMs);
  const minsLeft = Math.round(minutesUntil);

  const todayKey    = isoDate(new Date(now), tz);
  const tomorrowKey = isoDate(new Date(now + 86400000), tz);
  const eventKey    = isoDate(startDate, tz);
  const relativeDay =
    eventKey === todayKey ? 'Today'
    : eventKey === tomorrowKey ? 'Tomorrow'
    : dayStr(startDate, tz);

  // Guests list repeats the customer's own email — drop it.
  const otherGuests = (b.guests || []).filter(
    g => g.toLowerCase() !== (b.customerEmail || '').toLowerCase()
  );

  out.push({
    json: {
      reminderType: win.label,
      bookingId: b.bookingId,
      bookingUid: b.bookingUid,
      eventTypeSlug: b.eventTypeSlug,
      title: b.meetingTitle,

      // --- Person ---
      customerName: b.customerName || null,
      customerEmail: b.customerEmail || null,
      customerPhone: b.customerPhone || null,
      hasPhone: Boolean(b.customerPhone),

      // --- Formatted for messaging ---
      meetingDate: b.meetingDate,                       // "10 July 2026"
      meetingTime: b.meetingTime,                       // "2:30 pm"
      dayOfWeek: dayStr(startDate, tz),                 // "Friday"
      relativeDay,                                      // "Today"
      durationFormatted: humanDuration(b.durationMinutes),
      startsInFormatted: humanDuration(minsLeft),       // "1 hour 2 minutes"

      // --- Raw, for logic downstream ---
      minutesUntil: minsLeft,
      durationMinutes: b.durationMinutes,
      startTimeISO: b.startTimeISO,
      endTimeISO: b.endTimeISO,
      eventDate: eventKey,                              // "2026-07-10"
      timeZone: tz,

      meetingLink: b.meetingLink || null,
      agenda: b.agenda || '',
      hostName: b.hostName,
      hostEmail: b.hostEmail,
      guests: otherGuests,

      dedupeKey: `${b.bookingUid}:${win.label}`,
    },
  });
}

return out;
